from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Get the main subject (most triples)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s]))
    main_triples = subject_triples[main_subject]

    # Build sentence parts with proper grammar
    parts = []
    used_triples = set()

    # Handle industry/type first for company identity
    for triple in main_triples:
        if triple.predicate == 'industry':
            parts.append(f"{main_subject} operates in the {triple.object} industry")
            used_triples.add(triple)
            break

    for triple in main_triples:
        if triple.predicate == 'type':
            parts.append(f"it is a {triple.object}")
            used_triples.add(triple)
            break

    # Handle location predicates
    location_parts = []
    for triple in main_triples:
        if triple.predicate == 'country':
            location_parts.append(f"located in {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'city':
            location_parts.append(f"based in {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'location':
            location_parts.append(f"located in {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'foundationPlace':
            location_parts.append(f"founded in {triple.object}")
            used_triples.add(triple)

    if location_parts:
        parts.append(", ".join(location_parts))

    # Handle financial predicates
    financial_parts = []
    for triple in main_triples:
        if triple.predicate in ['netIncome', 'operatingIncome', 'revenue']:
            financial_parts.append(f"{triple.predicate.replace('Income', '').lower()} of {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'cost':
            financial_parts.append(f"costing {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'numberOfEmployees':
            financial_parts.append(f"{triple.object} employees")
            used_triples.add(triple)
        elif triple.predicate == 'numberOfLocations':
            financial_parts.append(f"{triple.object} locations")
            used_triples.add(triple)

    if financial_parts:
        parts.append(f"with {', '.join(financial_parts)}")

    # Handle personnel predicates
    for triple in main_triples:
        if triple.predicate == 'keyPerson':
            parts.append(f"key person is {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'leader':
            parts.append(f"led by {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'leaderParty':
            parts.append(f"leader belongs to {triple.object}")
            used_triples.add(triple)

    # Handle company relationships
    for triple in main_triples:
        if triple.predicate == 'subsidiary':
            parts.append(f"owns {triple.object}")
            used_triples.add(triple)
        elif triple.predicate == 'parentCompany':
            parts.append(f"a subsidiary of {triple.object}")
            used_triples.add(triple)

    # Handle remaining predicates
    for triple in main_triples:
        if triple not in used_triples:
            if triple.predicate == 'service':
                parts.append(f"provides {triple.object}")
            elif triple.predicate == 'product':
                parts.append(f"produces {triple.object}")
            else:
                parts.append(f"whose {triple.predicate} is {triple.object}")

    # Combine parts into a coherent sentence
    if len(parts) == 0:
        return f"{main_subject} is a company."
    elif len(parts) == 1:
        return f"{main_subject} is {parts[0]}."
    elif len(parts) == 2:
        return f"{main_subject} is {parts[0]}, {parts[1]}."
    else:
        # Build complex sentence with proper conjunctions
        result = f"{main_subject}"
        if parts[0].startswith(f"{main_subject}"):
            result = parts[0]
        else:
            result = f"{main_subject} is {parts[0]}"

        for i, part in enumerate(parts[1:], 1):
            if i == 1:
                result += f", {part}"
            else:
                result += f", and {part}"

        result += "."
        return result

# EVOLVE-BLOCK-END
